func (prg *prg) flushString(s strNumber) {
	if int32(s) < int32(prg.strPtr)-1 {
		prg.strRef[s] = 0
	} else {
		for {
			prg.strPtr = uint16(int32(prg.strPtr) - 1)
			if int32(prg.strRef[int32(prg.strPtr)-1]) != 0 {
				break
			}
		}
	}
	prg.poolPtr = prg.strStart[prg.strPtr]
}

