// Addition is not always checked to make sure that it doesn't overflow,
// but in places where overflow isn't too unlikely the |slow_add| routine
// is used.
func (prg *prg) slowAdd(x, y int32) (r int32) {
	if x >= 0 {
		if y <= 017777777777-x {
			r = x + y
		} else {
			prg.arithError = true
			r = 017777777777
		}
	} else if -y <= 017777777777+x {
		r = x + y
	} else {
		prg.arithError = true
		r = -017777777777
	}
	return r
}

