				x1 = x0 - prg.takeFraction(x0-x1, t)
				x2 = x1 - prg.takeFraction(x1-v, t)

				v = y1 - prg.takeFraction(y1-y2, t)
				y1 = y0 - prg.takeFraction(y0-y1, t)
				y2 = y1 - prg.takeFraction(y1-v, t)
